VALUES
  ('fire-eq-eng-moex-00161', 'fire-eq-eng', 'fire-eq-eng-moex-101-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依「建築技術規則」有關地下建築物之緩衝區規定，下列敘述何者錯誤？', '["緩衝區與連接之地下建築物、地下運輸系統及建築物之地下層間應以具有一小時以上防火時效之 牆壁、防火門窗等防火設備及該層防火構造之樓地板區劃分隔", "連接緩衝區二側之連接出入口，總寬度均應在三公尺以上，六公尺以下，且任一出入口淨寬度不 得小於一點五公尺", "緩衝區面積之百分之二十以上應挑空至地面層", "緩衝區內專供通行及緊急避難使用，不得有營業行為；牆壁得以耐燃一級材料設置嵌入式廣告物"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00162', 'fire-eq-eng', 'fire-eq-eng-moex-101-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依「建築技術規則」有關高層建築物規定，下列敘述何者錯誤？', '["高層建築物在二層以上，十六層或地板面高度在五十公尺以下之各樓層，應設置緊急進口。但面 臨道路或寬度四公尺以上之通路，且各層之外牆每十公尺設有窗戶或其他開口者，不在此限", "高層建築物應設置二座以上之特別安全梯並應符合二方向避難原則。二座特別安全梯應在不同平 面位置，其排煙室並不得共用", "高層建築物地板面高度在五十公尺以上或十六層以上之樓層應設置緊急昇降機間，緊急用昇降機 載重能力應達十七人（一千一百五十公斤）以上，其速度不得小於每分鐘六十公尺，且自避難層 至最上層應在一分鐘內抵達為限", "高層建築物之配管立管應考慮層間變位，消防、瓦斯等配管為二百分之一"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00163', 'fire-eq-eng', 'fire-eq-eng-moex-101-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依「原有合法建築物防火避難設施及消防設備改善辦法」規定，供何種類組建築物使用時，其消防 設備改善項目（室內消防栓、自動撒水設備、火警自動警報設備、緊急廣播設備、標示設備、緊急 照明設備、避難器具、瓦斯漏氣火警自動警報設備、排煙設備、滅火器、緊急電源配線）、內容及 方式，應依現行法令規定辦理改善？', '["Ａ類：公共集會類", "Ｂ類：商業類", "Ｃ類：工業、倉儲類", "Ｉ類：危險物品類"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00164', 'fire-eq-eng', 'fire-eq-eng-moex-101-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依「防焰性能認證實施要點」規定，下列敘述何者錯誤？', '["防焰物品或其材料之製造業者，品質管理部門至少應置一名以上之防焰處理技術人員", "防焰物品之防焰性能加工處理業者，應設有均勻浸泡、脫水、烘乾之設備；其浸泡之器具，應為 長一百公分以上、寬五十公分以上、高五十公分以上之水槽", "大型布幕無法以浸泡方式進行防焰性能加工處理時，得以噴霧塗布之方式，其噴霧器之噴嘴放射 壓力不得小於每平方公分三公斤", "窗簾、布幕，須經水洗及乾洗處理者，供防焰性能試驗之產品試樣規格為三平方公尺以上"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00165', 'fire-eq-eng', 'fire-eq-eng-moex-101-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依「消防法」及「明火表演安全管理辦法」規定，經申請許可餐廳之火把秀或酒吧魔術等明火表演 ，其所在樓層應有A座以上直通樓梯通達避難層，且任一點至該樓梯之步行路徑重複部分之長度， 不得大於最大容許步行距離B分之一；表演區域及外緣C公尺內之地面、牆面及地面上方D公尺以 內之天花板或樓板，不得以木板、未固著式泡綿、未具防焰性能之布幕等易引發火災之材料裝潢或 裝飾，請問前述A，B，C，D為何？', '["3，3，5，5", "2，2，2，6", "1，2，1，3", "2，3，1，4"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00166', 'fire-eq-eng', 'fire-eq-eng-moex-101-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依「消防法施行細則」規定，下列敘述何者錯誤？', '["受託執行檢驗消防機具、器材與設備之機關（構）、學校、團體，其檢驗設備、員額、技術能力 、檢驗紀錄、檢驗時效、樣品管理及其他事項，中央主管機關至少每年檢討考核一次", "廠商申請消防機具、器材及設備認可檢驗時，應填具申請書並檢送試樣及相關資料，向中央主管 機關或其委託之檢驗單位提出，經取得型式承認後，應依檢定作業規定於二年內申請個別檢定， 檢定合格者，核發合格標示", "防火管理人每二年至少應接受講習訓練一次", "消防防護計畫中滅火、通報及避難訓練之實施；每半年至少應舉辦一次"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00001', 'fire-eq-tech', 'fire-eq-tech-moex-114-a98764b7', 'sub-fire-eq-tech-01', NULL, 'essay', '請說明乾粉滅火藥劑之滅火原理？（10分）乾粉滅火藥劑種類及主要成
